```typescript
'use server';
import { Resend } from 'resend';
import { createClient } from '@/lib/supabase/server';

export async function createNotice(eventId: string, formData: FormData) {
  const content = formData.get('content') as string;
  const sendEmail = formData.get('send_email') === 'true';

  const supabase = await createClient();

  // 공지 저장
  const { error } = await supabase
    .from('notices')
    .insert({ event_id: eventId, content, send_email: sendEmail });

  if (error) throw new Error(error.message);

  // 이메일 발송 (sendEmail이 true인 경우)
  if (sendEmail) {
    const { data: event } = await supabase
      .from('events').select('title').eq('id', eventId).single();

    const { data: recipients } = await supabase
      .from('participants')
      .select('name, email')
      .eq('event_id', eventId)
      .eq('status', 'applied')
      .eq('is_email_opt_in', true)
      .not('email', 'is', null);

    if (recipients && recipients.length > 0) {
      const resend = new Resend(process.env.RESEND_API_KEY);
      await Promise.all(
        recipients.map(p =>
          resend.emails.send({
            from: 'GroupMeet <noreply@yourdomain.com>',
            to: p.email!,
            subject: `[${event?.title}] 새 공지가 등록되었습니다`,
            html: `<p>${p.name}님,</p><p>${content}</p>`,
          })
        )
      );
    }
  }
}
```

