'use server';
import { createClient } from '@/lib/supabase/server';
import { applyParticipantSchema } from '@/lib/validations';

export async function applyToEvent(eventId: string, formData: FormData) {
  const parsed = applyParticipantSchema.parse({
    name: formData.get('name'),
    email: formData.get('email') || undefined,
    is_email_opt_in: formData.get('is_email_opt_in') === 'true',
  });

  // 이메일 없으면 opt_in false 강제
  if (!parsed.email) parsed.is_email_opt_in = false;

  const supabase = await createClient();
  const { data, error } = await supabase
    .from('participants')
    .insert({
      event_id: eventId,
      name: parsed.name,
      email: parsed.email || null,
      is_email_opt_in: parsed.is_email_opt_in,
      status: 'applied',
    })
    .select('id')
    .single();

  if (error) throw new Error(error.message);
  return { participantId: data.id };
}

export async function cancelParticipation(participantId: string) {
  const supabase = await createClient();
  const { error } = await supabase
    .from('participants')
    .update({ status: 'canceled' })
    .eq('id', participantId);
  if (error) throw new Error(error.message);
}
